mapper.select:
SELECT o.order_id, o.order_no, o.customer_id, o.business_id, o.bid_id, o.total_amount, o.payment_status, o.accept_status, o.delivery_status, o.created_at FROM orders o WHERE o.customer_id = #{customerId} AND o.payment_status = 'PAID' AND o.customer_deleted = 0
AND EXISTS ( SELECT 1 FROM order_items oi LEFT JOIN kit k ON k.kit_id = oi.kit_id LEFT JOIN bids b ON b.bid_id = o.bid_id LEFT JOIN request r ON r.request_id = b.request_id WHERE oi.order_id = o.order_id AND ( k.name LIKE CONCAT('%', #{search.keyword}, '%') OR r.title LIKE CONCAT('%', #{search.keyword}, '%') ) )
AND o.created_at >= #{search.startDate}
AND o.created_at < DATE_ADD(#{search.endDate}, INTERVAL 1 DAY)
ORDER BY o.created_at DESC LIMIT #{limit} OFFSET #{offset}

mapper.delete:
DELETE FROM review
WHERE order_item_id IN (
    SELECT order_item_id FROM order_items WHERE order_id = #{orderId}
)

mapper.update:
UPDATE orders
SET customer_deleted = 1
WHERE order_id = #{orderId}
